import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"25. Modes Of Employment","description":"","frontmatter":{"title":"25. Modes Of Employment","eba":"Mental Health Services 2024-2028","topics":["hours","employment","classifications"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/employment-types/25-modes-of-employment.md","filePath":"ebas/mental-health/common-terms/employment-types/25-modes-of-employment.md"}'),r={name:"ebas/mental-health/common-terms/employment-types/25-modes-of-employment.md"};function s(i,e,l,p,m,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_25-modes-of-employment" tabindex="-1">25. Modes Of Employment <a class="header-anchor" href="#_25-modes-of-employment" aria-label="Permalink to &quot;25. Modes Of Employment&quot;">​</a></h1><p><strong>25.1</strong> Full-time Employment</p><p><strong>(a)</strong> A full-time Employee is one who is engaged to work 38 hours per week or an average of 38 hours as per <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/88-hours-of-work.html">clauses 88</a>, 122, 164 and 199 (Hours of Work).</p><p><strong>(b)</strong> A full-time Employee who is ready, willing and able to work full-time hours will be paid the weekly salary appropriate to the Employee’s classification, irrespective of the number of hours worked not exceeding 38, or an average of 38 per week.</p><p><strong>25.2</strong> Part-time Employment</p><p><strong>(a)</strong> A part-time Employee is one who is engaged to work less than an average of 38 hours per week.</p><p><strong>(b)</strong> The number of hours worked by a part-time Employee may vary from week to week by mutual agreement.</p><p><strong>(c)</strong> A part-time Employee will be paid an hourly rate equal to 1/38th of the weekly salary for the Employee’s classification. Payments for shift work (<a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/75-change-of-shift-allowance-pen-and-mho.html">clauses 75</a>, 84, 157, 178 and 194), for Saturday and Sunday (<a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/83-saturday-and-sunday-work.html">clauses 83</a>, 130, 177 and 209) and public holiday work (<a href="/eba/ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.html">clauses 98</a>, 135, 179 and 213 ) also apply to part-time Employees.</p><p><strong>(d)</strong> Where a part-time Employee has an entitlement to leave under this Agreement, the part-time Employee will be paid according to the number of hours the Employee would have worked on the day/s on which the leave was taken.</p><p><strong>(e)</strong> Notwithstanding the above, a part-time MHO employed on a regular basis for four hours or less per week shall be paid in accordance with clause 25.3.</p><p><strong>(f)</strong> Where a full-time Employee converts from full-time to part-time, the Employer shall not reduce the total EFT of the Employee’s workplace as a result of the conversion to part-time.</p><p><strong>25.3</strong> Converting from Full-Time Employment to Part-time Employment</p><p><strong>(a)</strong> A full time Employee may, by agreement with the Employer, convert to part time arrangements.</p><p><strong>(b)</strong> Where a full time Employee converts from full time to part time, the Employer shall not reduce the total EFT of the Employee’s workplace as a result of the conversion to part time.</p><p><strong>25.4</strong> Casual Employment</p><p><strong>(a)</strong> The persons covered by this Agreement confirm their commitment to maximise full time and part time employment and agree that the engagement of casual Employees shall, subject to <a href="/eba/ebas/mental-health/rpn-pen-mho/classification-staffing/101-staffing.html">clause 101.13</a> (Section 2 - Registered Psychiatric Nurses/Enrolled Nurses &amp; MHO&#39;s, Part H: Classification &amp; Staffing) be only in response to unplanned circumstances (without intending to be exhaustive, such as filling of gaps in rosters caused by sick leave or other unpredictable absences). Casual employment is not to be used in circumstances where the work undertaken is of an ongoing and predictable nature. It will be the aim to utilise existing Employees for unplanned absences where practicable.</p><p><strong>(b)</strong> A casual Employee:</p><p><strong>(i)</strong> is an Employee who:</p><p><strong>(A)</strong> is made an offer of employment on the basis that the Employer makes no firm advance commitment to continuing and indefinite work (e.g. relief such as replacing an employee on an unplanned absence); and <strong>(B)</strong> accepts the offer of employment on that basis <strong>(C)</strong> is paid in accordance with sub-clause 25.4(e) and (f) of this Agreement; and <strong>(D)</strong> is an Employee as a result of that acceptance.</p><p><strong>(c)</strong> When determining whether an Employer has made an offer of employment in accordance with subclause 25.4(b)(i)(A), regard is to be had to the Act which presently provides for consideration of the following indicia:</p><p><strong>(i)</strong> the &quot;real substance, practical reality and a true nature of the employment relationship&quot;, including whether a firm advanced commitment has arisen by reason of:</p><p><strong>(ii)</strong> the Employee&#39;s contract of employment; or</p><p><strong>(iii)</strong> a mutual understanding or expectation that has arisen between the Employer and the Employee (not rising to the level of a term of that contract or to a variation of any such term); and</p><p><strong>(iv)</strong> having regard to, but not limited to, the following considerations (which may indicate the presence, rather than absence, of such a commitment):</p><p><strong>(v)</strong> whether there is an inability of the Employer to elect to offer, or not offer, work to the Employee;</p><p><strong>(vi)</strong> whether there is an ability of the Employee to elect to accept or reject work (and whether this occurs in practice);</p><p><strong>(vii)</strong> whether, having regard to the nature of the Employer&#39;s enterprise, it is reasonably likely that there will be future availability of continuing work in that enterprise of the kind usually performed by the Employee</p><p><strong>(viii)</strong> whether there are full-time Employees or part-time Employees performing the same kind of work in the Employer&#39;s enterprise that is usually performed by the Employee; and</p><p><strong>(ix)</strong> whether there is a regular pattern of work for the Employee.</p><p><strong>(d)</strong> A casual Employee’s engagement is terminable without prior notice by either party subject to the applicable minimum engagement <a href="/eba/ebas/mental-health/support-services/preliminary/167-minimum-engagement.html">clauses 167</a> and 201.</p><p><strong>(e)</strong> A casual Nurse or MHO Employee will be paid an hourly rate equal to 1/38th of the weekly salary for the Employee’s classification plus 25% for ordinary hours worked during the week. Payments for shift work (<a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/84-shift-allowances.html">clause 84</a>), weekend work (<a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/83-saturday-and-sunday-work.html">clause 83</a>) and public holiday work (<a href="/eba/ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.html">clause 98</a>) also apply to casual Employees.</p><p><strong>(f)</strong> For Employees under Section 3, 4 and 5 of this Agreement a casual Employee shall be paid for all work done on a weekdays an amount equal to 1/38th of the weekly wage appropriate to the Employees classification per hour plus 25% and for all work done Saturday, Sundays and Public Holidays an amount equal to 1/38th of the weekly wage appropriate to the Employees classification per hour plus 75%.</p><p><strong>(g)</strong> Except where expressly excluded, a casual Employee will be entitled to receive the allowances prescribed by Section 1, Part E of this Agreement.</p><p><strong>(h)</strong> A casual Employee will not be entitled to the following provisions of the agreement:</p><p><strong>(i)</strong> annual leave (<a href="/eba/ebas/mental-health/common-terms/leave/38D-annual-leave.html">clause 38D</a>)</p><p><strong>(ii)</strong> purchased leave (<a href="/eba/ebas/mental-health/common-terms/leave/51-purchased-leave.html">clause 51</a>)</p><p><strong>(iii)</strong> paid personal leave (<a href="/eba/ebas/mental-health/common-terms/leave/38A-personal-leave.html">clause 38A</a>)</p><p><strong>(iv)</strong> paid compassionate leave (<a href="/eba/ebas/mental-health/common-terms/leave/44-compassionate-leave.html">clause 44</a>)</p><p><strong>(v)</strong> long service leave – Health Professionals (Note: State LSL Act applies) (<a href="/eba/ebas/mental-health/common-terms/leave/47-long-service-leave.html">clause 47</a>)</p><p><strong>(vi)</strong> professional development leave (<a href="/eba/ebas/mental-health/rpn-pen-mho/education-pd/99-professional-development-leave.html">clauses 99.1</a>, 99.2 , 136 and 218) other than <a href="/eba/ebas/mental-health/rpn-pen-mho/education-pd/99-professional-development-leave.html">clause 99.8</a> (mandatory training) which does apply to casual Employees;</p><p><strong>(vii)</strong> study leave (<a href="/eba/ebas/mental-health/rpn-pen-mho/education-pd/99A-study-leave.html">clauses 99A.3</a>, 139, 140, 180 and 214)</p><p><strong>(viii)</strong> examination leave (<a href="/eba/ebas/mental-health/rpn-pen-mho/education-pd/99B-examination-leave-rpn-and-pen.html">clauses 99B</a>, 137 and 215)</p><p><strong>(ix)</strong> rosters (<a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/94-rosters.html">clauses 94.8</a> and 173.4 and 222A</p><p><strong>(x)</strong> notice period before termination (<a href="/eba/ebas/mental-health/health-professionals/employment-types/112-this-clause-is-deliberately-blank.html">clause 112</a>)</p><p><strong>(xi)</strong> absences on defence leave (<a href="/eba/ebas/mental-health/common-terms/leave/40-absence-on-defence-leave.html">clause 40</a>)</p><p><strong>(xii)</strong> special disaster leave (<a href="/eba/ebas/mental-health/common-terms/leave/41-special-disaster-leave.html">clause 41</a>)</p><p><strong>(i)</strong> A casual Employee is entitled to the following:</p><p><strong>(i)</strong> unpaid personal leave for carer’s responsibilities (<a href="/eba/ebas/mental-health/common-terms/leave/38C-caring-responsibilities-casual-employees.html">clause 38C</a>)</p><p><strong>(ii)</strong> unpaid compassionate leave (<a href="/eba/ebas/mental-health/common-terms/leave/44-compassionate-leave.html">clause 44</a>)</p><p><strong>(iii)</strong> parental leave (<a href="/eba/ebas/mental-health/common-terms/leave/50-parental-leave.html">clause 50</a>) subject to the eligibility requirements of that clause</p><p><strong>(iv)</strong> Paid and unpaid family and domestic violence leave (<a href="/eba/ebas/mental-health/common-terms/leave/45-family-and-domestic-violence-leave.html">clause 45</a>)</p><p><strong>(v)</strong> Paid and unpaid cultural and ceremonial leave (<a href="/eba/ebas/mental-health/common-terms/leave/43-ceremonial-leave.html">clause 43</a>)</p><p><strong>(vi)</strong> Unpaid gender affirmation leave</p><p><strong>(vii)</strong> Unpaid pre-adoption leave (<a href="/eba/ebas/mental-health/common-terms/leave/48-pre-adoption-leave.html">clause 48</a>); and</p><p><strong>(viii)</strong> All other applicable terms of the Agreement</p><p><strong>(j)</strong> In terms of Employees covered by Section 2 of the Agreement, any casual replacement shift shall be of the same shift length as the shift that is being replaced. Additional casual Employees for unexpected periods of peak workload may be of shorter duration.</p><p><strong>(k)</strong> Further to clause 25.4(j), it is acknowledged that in the event of logistical difficulties such as late notification of personal leave or genuine inability to obtain an agency/bank nurse for a full shift replacement then the full shift replacement may not be able to occur.</p><p><strong>(l)</strong> A casual Employee may convert to a full time or part time Employee in accordance with <a href="/eba/ebas/mental-health/common-terms/employment-types/26-casual-conversion.html">clause 26</a> below.</p><p><strong>25.5</strong> Fixed Term Employment</p><p><strong>(a)</strong> A Fixed term Employee is an Employee who is employed:</p><p><strong>(i)</strong> for a specified period of time, which period is known at the commencement of the contract, or</p><p><strong>(ii)</strong> for a specified task such as a project or replacement of an absent employee; or</p><p><strong>(iii)</strong> for a fixed period.</p><p><strong>(b)</strong> Subject to 25.6 , fixed term employment will not be used to fill an ongoing position.</p><p><strong>25.6</strong> Limitations on the use of fixed term contracts</p><p><strong>(a)</strong> Subject to subclause 25.6(b), the following limitations apply to the use of fixed term contracts:</p><p><strong>(i)</strong> the fixed term contract will not be for an employment term of longer than 2 years, including any extensions or renewals</p><p><strong>(ii)</strong> a fixed term contract will not include an option to extend or renew the Employee&#39;s employment more than once, or extend or renew such that employment period would be longer than 2 years; and</p><p><strong>(iii)</strong> the Employer will not offer an Employee a fixed term contract if it is to come into effect after another contract of employment if: <strong>(A)</strong> the previous contract included a term that provided the contract would terminate at the end of an identifiable period <strong>(B)</strong> under the previous contract, the Employee was to perform the same, or substantially similar work to that which they are or would be required to work under the new contract; and <strong>(C)</strong> at least one of the following applies: 1) the previous contract contained an option to extend, and the contract was extended; or 2) the total employment period will now be more than 2 years; or 3) the new contract contains an option to renew or extend; or 4) the previous contract came into effect after another contract which specified termination at the end of an identifiable period, there was substantial continuity in the employment relationship during the period of the initial contract termination and the previous contract taking effect.</p><p><strong>(b)</strong> The limitations at 25.6(a)25.6(a) do not apply where:</p><p><strong>(i)</strong> the Employee is working on a specific task requiring specialised skills not usually available through Employees of the Employer; or</p><p><strong>(ii)</strong> the Employee&#39;s engagement is for the duration of a training arrangement; or</p><p><strong>(iii)</strong> the Employee is performing essential work during a peak demand period; or</p><p><strong>(iv)</strong> the Employee is working during emergency circumstances or replacing another Employee who is temporarily absent; or</p><p><strong>(v)</strong> the Employee&#39;s income is above the high-income threshold (which is provided for in the Act); or</p><p><strong>(vi)</strong> the Employee&#39;s position is partially or fully funded by government funding, which has been granted for a set period which is more than 2 years but is unlikely to be renewed</p><p><strong>(vii)</strong> the contract relates to a governance position that has a relevant time limit</p><p><strong>(viii)</strong> a modern award that covers the Employee otherwise allows for the use of a Fixed Term Contract; or</p><p><strong>(ix)</strong> the contract is of a kind prescribed by the FW Regulations.</p><p><strong>(c)</strong> Examples of where fixed term employment may be appropriate include:</p><p><strong>(i)</strong> RUSON positions</p><p><strong>(ii)</strong> Graduate positions</p><p><strong>(iii)</strong> Post Graduate training positions</p><p><strong>(iv)</strong> Long term WorkCover replacement</p><p><strong>(v)</strong> Special Projects</p><p><strong>(vi)</strong> Positions created through identifiable funding external to the Employer not being funding that is part of an operating grant from government; and</p><p><strong>(vii)</strong> Backfill including for extended leave (such as Parental Leave and Long Service Leave) and to support flexible working arrangements</p><p><strong>(viii)</strong> Aboriginal Traineeship</p><p><strong>(ix)</strong> Aboriginal Cadetship</p><p><strong>(x)</strong> Pre-Qualification Health Professional Students Note: In this context, backfill to support flexible working arrangements does not refer to the Employee on the flexible working arrangement, but instead to an arrangement to work hours that arise from a flexible work arrangement that includes a temporary reduction in hours.</p><p><strong>25.7</strong> If an Employer and Employee enter into a fixed term contract which is not permitted under this Agreement, the term of the contract that provides that it will terminate at the end of an identifiable period is taken to have no effect, and the validity of the contract will otherwise not be affected.</p><p><strong>25.8</strong> General features of fixed term contracts</p><p><strong>(a)</strong> An Employee who continues working in the same role for the Employer following the expiry date of a fixed term contract, may, in accordance with the Act, be deemed a permanent Employee.</p><p><strong>(b)</strong> An Employer must specify the rationale for fixed term employment, in the Employee’s Letter of Appointment.</p><p><strong>(c)</strong> An Employee may terminate the fixed term employment by the giving of notice in accordance with <a href="/eba/ebas/mental-health/common-terms/employment-types/28-termination-of-employment.html">clause 28</a> of this Agreement. No notice is required when the contract reaches its expiry date.</p><p><strong>(d)</strong> An Employer may terminate a fixed term Employee in accordance with <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/24-managing-conduct-and-performance.html">clause 24</a> or <a href="/eba/ebas/mental-health/common-terms/employment-types/28-termination-of-employment.html">clause 28</a>.</p><p>Plain language terms: employment types, full time, part time, casual, fixed term.</p>',97)])])}const d=t(r,[["render",s]]);export{g as __pageData,d as default};
